import{_ as t,o as r,c as e,a2 as i}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"保证金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"margin/margin-requirements.md","filePath":"zh-CN/margin/margin-requirements.md"}'),l={name:"margin/margin-requirements.md"};function o(h,a,n,p,d,s){return r(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="保证金" tabindex="-1">保证金 <a class="header-anchor" href="#保证金" aria-label="Permalink to &quot;保证金&quot;">​</a></h1><p>保证金是持有融资仓位所需的最低资产要求，本页说明三层保证金结构、货币保证金规则及追缴保证金（Margin Call）机制。</p><hr><h2 id="保证金三层结构" tabindex="-1">保证金三层结构 <a class="header-anchor" href="#保证金三层结构" aria-label="Permalink to &quot;保证金三层结构&quot;">​</a></h2><p>账户设有三层保证金机制：</p><table tabindex="0"><thead><tr><th>层次</th><th>缩写</th><th>含义</th><th>触发后果</th></tr></thead><tbody><tr><td>初始保证金</td><td>IM</td><td>开仓时所需的最低保证金，决定购买力上限</td><td>股权资产 &lt; IM → 购买力用尽，不可新开仓</td></tr><tr><td>维持保证金</td><td>MM</td><td>持仓期间需维持的最低保证金</td><td>股权资产 &lt; MM → 发出追缴保证金通知</td></tr><tr><td>平仓保证金</td><td>FM</td><td>强制平仓的触发线</td><td>股权资产 &lt; FM → 可能即时强制平仓</td></tr></tbody></table><h2 id="保证金要求计算" tabindex="-1">保证金要求计算 <a class="header-anchor" href="#保证金要求计算" aria-label="Permalink to &quot;保证金要求计算&quot;">​</a></h2><p>各层保证金要求按持仓加总计算：</p><p>保证金要求 = 加总（各持仓市值 × 对应保证金系数）</p><p>不同证券的 IM / MM / FM 系数各不相同，具体系数以平台公示为准。各证券保证金系数请以平台实时公示为准，不同市场、不同标的系数存在差异。</p><h2 id="关键指标定义" tabindex="-1">关键指标定义 <a class="header-anchor" href="#关键指标定义" aria-label="Permalink to &quot;关键指标定义&quot;">​</a></h2><p>股权资产 = 现金余额 + 投资组合总市值</p><p>可用资金（含融资）= 股权资产 - 初始保证金要求 - 冻结资金</p><p>最大购买力 = 可用资金 ÷ 初始保证金系数（IM Ratio）</p><h2 id="购买力计算示例" tabindex="-1">购买力计算示例 <a class="header-anchor" href="#购买力计算示例" aria-label="Permalink to &quot;购买力计算示例&quot;">​</a></h2><p>存入现金 $10,000，账户融资额度 $20,000，目标标的 IM 系数为 30%：</p><p>可用资金 = $10,000 - $0（当前无持仓，IM 要求为 0）- $0 = $10,000</p><p>理论最大购买力 = $10,000 ÷ 30% ≈ $33,333</p><p>但实际受融资额度限制，最多融资 $20,000，因此实际最大购买力 = $10,000 + $20,000 = $30,000</p><p>购买后融资结欠 = $20,000，未超过融资额度上限，符合要求。</p><hr><h2 id="货币保证金" tabindex="-1">货币保证金 <a class="header-anchor" href="#货币保证金" aria-label="Permalink to &quot;货币保证金&quot;">​</a></h2><p>当账户持有的货币与投资标的计价货币不同时（如用港元账户购买美元计价的美股），存在汇率波动风险。平台会对此类跨币种持仓额外收取货币保证金。</p><h3 id="货币保证金的触发条件" tabindex="-1">货币保证金的触发条件 <a class="header-anchor" href="#货币保证金的触发条件" aria-label="Permalink to &quot;货币保证金的触发条件&quot;">​</a></h3><p>当某种货币的资产净值为负（即该货币资不抵债）时，触发货币保证金计算。</p><p>货币保证金 = 该货币负债金额 × 货币保证金比率</p><h3 id="货币保证金比率" tabindex="-1">货币保证金比率 <a class="header-anchor" href="#货币保证金比率" aria-label="Permalink to &quot;货币保证金比率&quot;">​</a></h3><p>以下比率以平台实时公示为准：</p><p>美元（USD）：4%</p><p>港元（HKD）：4%</p><h3 id="货币保证金示例" tabindex="-1">货币保证金示例 <a class="header-anchor" href="#货币保证金示例" aria-label="Permalink to &quot;货币保证金示例&quot;">​</a></h3><p>账户存入 20,000 HKD，未持有美元。</p><p>购入价值 2,000 USD 的美股（此时美元持仓为 -2,000 USD，即借入美元）。</p><p>之后美股市值下跌至 1,900 USD。</p><p>此时美元资产净值 = 1,900 USD（持仓市值）- 2,000 USD（借入成本）= -100 USD，即美元资不抵债 100 USD。</p><p>货币保证金 = 100 USD × 4% = 4 USD</p><h3 id="对账户指标的影响" tabindex="-1">对账户指标的影响 <a class="header-anchor" href="#对账户指标的影响" aria-label="Permalink to &quot;对账户指标的影响&quot;">​</a></h3><p>货币保证金会计入以下计算：</p><p><strong>购买力</strong>：货币保证金作为额外占用，降低可用购买力。</p><p><strong>出金可用金额</strong>：出金时需预留货币保证金，超出部分方可出金。</p><p><strong>追缴保证金</strong>：触发追缴时，货币保证金纳入差额计算。</p><p><a href="https://longbridgeapp.com/zh-CN/topics/2078132" target="_blank" rel="noreferrer">参考链接</a></p><hr><h2 id="追缴保证金-margin-call" tabindex="-1">追缴保证金（Margin Call） <a class="header-anchor" href="#追缴保证金-margin-call" aria-label="Permalink to &quot;追缴保证金（Margin Call）&quot;">​</a></h2><p>当账户股权资产低于维持保证金要求时，平台将发出追缴保证金通知，要求在规定时间内补足差额，否则可能触发强制平仓。</p><h3 id="追缴触发条件" tabindex="-1">追缴触发条件 <a class="header-anchor" href="#追缴触发条件" aria-label="Permalink to &quot;追缴触发条件&quot;">​</a></h3><p>股权资产 &lt; 维持保证金要求（MM）</p><h3 id="追缴处理期限" tabindex="-1">追缴处理期限 <a class="header-anchor" href="#追缴处理期限" aria-label="Permalink to &quot;追缴处理期限&quot;">​</a></h3><p>收到追缴通知后，须在 3 个交易日内（含当日）补足差额。</p><p>追缴金额 = 维持保证金要求 - 股权资产（高于两者差额）</p><blockquote><p>应对步骤（存入现金或卖出持仓的操作路径）见<a href="/wiki/margin/how-to-respond-to-margin-call">如何应对追加保证金通知</a>。</p></blockquote><h3 id="强制平仓触发条件" tabindex="-1">强制平仓触发条件 <a class="header-anchor" href="#强制平仓触发条件" aria-label="Permalink to &quot;强制平仓触发条件&quot;">​</a></h3><p>股权资产 &lt; 强平保证金要求（FM）时，平台可能即时强制平仓，无需等待 3 个交易日。</p><p>以下高风险情况可能不等待追缴期，直接触发强平：</p><ul><li>末日期权（到期日当天的期权）持仓</li><li>市场出现极端波动</li><li>持仓流动性不足，无法正常变现</li></ul><h3 id="追缴保证金完整示例" tabindex="-1">追缴保证金完整示例 <a class="header-anchor" href="#追缴保证金完整示例" aria-label="Permalink to &quot;追缴保证金完整示例&quot;">​</a></h3><p>账户存入现金 $10,000，同时持有 A 股票市值 $5,000（IM 30% / MM 25%）。</p><p>使用融资购入 B 股票，买入价 $25,000（IM 50% / MM 45%）。</p><p>之后 B 股票市值下跌至 $19,500。</p><p>此时各项指标：</p><p>股权资产 = $10,000（现金）+ $5,000（A）+ $19,500（B）- $25,000（融资结欠）= $9,500</p><p>维持保证金要求 = $5,000 × 25% + $19,500 × 45% = $1,250 + $8,775 = $10,025</p><p>股权资产 $9,500 &lt; 维持保证金要求 $10,025，触发追缴。</p><p>追缴金额 = $10,025 - $9,500 = $525（实际追缴金额高于此差额，需补至初始保证金水平）</p><p>实际追缴金额及截止时间请以账户内通知为准。</p><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/margin/credit-limit">融资额度</a> — 额度评估、降低与关闭操作</li><li><a href="/wiki/margin/risk-control">账户风控</a> — 安全/中等/预警/危险四级风控状态与购买力影响</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/derivatives/options/options-seller">期权卖方</a></li><li><a href="/wiki/margin/credit-limit">融资额度</a></li><li><a href="/wiki/margin/how-to-respond-to-margin-call">如何应对追加保证金通知</a></li><li><a href="/wiki/margin">融资融券</a></li><li><a href="/wiki/margin/interest-rules">融资利息</a></li><li><a href="/wiki/margin/risk-control">账户风控</a></li></ul>',70)])])}const m=t(l,[["render",o]]);export{u as __pageData,m as default};
